"""module: data_processor.py — a fully annotated example."""
from typing import Optional, Union
from datetime import datetime

# ─── Primitive types ──────────────────────────────────────────────────────────

def add(x: int, y: int) -> int:
    """Add two integers and return the result."""
    return x + y

def divide(a: float, b: float) -> float:
    """Divide a by b."""
    if b == 0:
        raise ValueError("Division by zero")
    return a / b

def is_valid_email(email: str) -> bool:
    """Return True if email looks plausible."""
    return "@" in email and "." in email.split("@")[-1]

# ─── Optional types ───────────────────────────────────────────────────────────

def find_user(user_id: int) -> Optional[str]:
    """Look up user name by ID, returning None if not found."""
    users = {1: "Alice", 2: "Bob"}
    return users.get(user_id)

# Python 3.10+ equivalent:
def find_user_310(user_id: int) -> str | None:
    users = {1: "Alice", 2: "Bob"}
    return users.get(user_id)

# ─── Union types ──────────────────────────────────────────────────────────────

def parse_number(value: Union[str, int, float]) -> float:
    """Convert string, int, or float to float."""
    return float(value)

# Python 3.10+ equivalent:
def parse_number_310(value: str | int | float) -> float:
    return float(value)

# ─── Container types ─────────────────────────────────────────────────────────

def average(numbers: list[float]) -> float:
    """Return arithmetic mean of a list of floats."""
    if not numbers:
        raise ValueError("Empty list")
    return sum(numbers) / len(numbers)

def word_frequencies(text: str) -> dict[str, int]:
    """Count occurrences of each word in text."""
    freq: dict[str, int] = {}
    for word in text.lower().split():
        freq[word] = freq.get(word, 0) + 1
    return freq

def to_pairs(keys: list[str], values: list[int]) -> list[tuple[str, int]]:
    """Zip two lists into a list of (str, int) pairs."""
    return list(zip(keys, values))

# ─── Class with annotated attributes ─────────────────────────────────────────

class Event:
    name: str
    timestamp: datetime
    tags: list[str]
    metadata: dict[str, Union[str, int, float]]

    def __init__(
        self,
        name: str,
        timestamp: Optional[datetime] = None,
        tags: Optional[list[str]] = None,
    ) -> None:
        self.name = name
        self.timestamp = timestamp or datetime.utcnow()
        self.tags = tags or []
        self.metadata: dict[str, Union[str, int, float]] = {}

    def add_tag(self, tag: str) -> None:
        """Add a tag to the event."""
        if tag not in self.tags:
            self.tags.append(tag)

    def summarize(self) -> str:
        """Return a one-line summary."""
        return f"{self.name} at {self.timestamp.isoformat()} [{', '.join(self.tags)}]"

from typing import Optional, Union, Any, Callable, Iterable, Sequence
from typing import Set, FrozenSet, Tuple
from collections.abc import Iterator, Generator

# None return type (procedures)
def configure(debug: bool) -> None:
    pass  # returns None

# Multiple return types
def min_max(values: list[float]) -> tuple[float, float]:
    return min(values), max(values)

# Immutable sequences
def read_config(path: str) -> tuple[str, int, bool]:
    # Returns exactly (host, port, ssl) — fixed-length tuple
    return ("localhost", 8080, False)

# Sets
def unique_tags(items: list[dict[str, list[str]]]) -> set[str]:
    result: set[str] = set()
    for item in items:
        for tag_list in item.values():
            result.update(tag_list)
    return result

# Callable types
def apply_transform(
    values: list[float],
    transform: Callable[[float], float],
) -> list[float]:
    return [transform(v) for v in values]

# Usage: apply_transform([1.0, 2.0, 3.0], lambda x: x ** 2)

# Iterator and Generator
def count_up(start: int, stop: int) -> Iterator[int]:
    n = start
    while n < stop:
        yield n
        n += 1

def fibonacci() -> Generator[int, None, None]:
    a, b = 0, 1
    while True:
        yield a
        a, b = b, a + b

# Any — explicit opt-out of type checking
def debug_print(value: Any) -> None:
    print(f"DEBUG: {value!r} (type: {type(value).__name__})")

# Callback with complex signature
Handler = Callable[[str, int], Optional[str]]

def register_handler(event: str, handler: Handler) -> None:
    print(f"Registered handler for {event!r}")

from typing import Union, Optional

def process(value: str | None) -> str:
    # After the guard, mypy knows value is str (not None)
    if value is None:
        return "default"
    # Here, value: str (narrowed)
    return value.upper()

def describe(x: int | str | list[int]) -> str:
    if isinstance(x, int):
        # x: int here
        return f"integer: {x}"
    elif isinstance(x, str):
        # x: str here
        return f"string: '{x}'"
    else:
        # x: list[int] here
        return f"list of {len(x)} integers"

# Type narrowing works with isinstance, issubclass, type() checks,
# is/is not None checks, and truthiness checks for Optional types.
val: Optional[str] = "hello"
if val:
    # mypy knows val is str (not None and not empty)
    print(val.upper())

# TypeGuard (Python 3.10+) for custom narrowing predicates
from typing import TypeGuard

def is_string_list(val: list[object]) -> TypeGuard[list[str]]:
    return all(isinstance(x, str) for x in val)

items: list[object] = ["a", "b", "c"]
if is_string_list(items):
    # mypy narrows: items is list[str] here
    result = ", ".join(items)

from fastapi import FastAPI, HTTPException, Query
from pydantic import BaseModel, Field, EmailStr
from typing import Optional
from datetime import datetime
import uvicorn

app = FastAPI(title="User API", version="1.0.0")

# Pydantic models use type annotations for validation schema
class UserCreate(BaseModel):
    username: str = Field(..., min_length=3, max_length=50)
    email: EmailStr
    age: int = Field(..., ge=0, le=150)
    bio: Optional[str] = Field(None, max_length=500)

class UserResponse(BaseModel):
    id: int
    username: str
    email: str
    created_at: datetime

    class Config:
        from_attributes = True

# In-memory store for demo
users: dict[int, dict] = {}
next_id = 1

@app.post("/users", response_model=UserResponse, status_code=201)
def create_user(user: UserCreate) -> UserResponse:
    """Create a new user. Body is validated against UserCreate schema."""
    global next_id
    record = {
        "id": next_id,
        "username": user.username,
        "email": user.email,
        "created_at": datetime.utcnow(),
    }
    users[next_id] = record
    next_id += 1
    return UserResponse(**record)

@app.get("/users/{user_id}", response_model=UserResponse)
def get_user(user_id: int) -> UserResponse:
    """Retrieve user by ID. 404 if not found."""
    if user_id not in users:
        raise HTTPException(status_code=404, detail="User not found")
    return UserResponse(**users[user_id])

@app.get("/users", response_model=list[UserResponse])
def list_users(
    limit: int = Query(10, ge=1, le=100),
    offset: int = Query(0, ge=0),
) -> list[UserResponse]:
    """List users with pagination. Query params are typed and validated."""
    items = list(users.values())[offset : offset + limit]
    return [UserResponse(**u) for u in items]

