# beartype: add runtime type enforcement with a decorator
from beartype import beartype

@beartype
def greet(name: str, times: int) -> str:
    return ("Hello, " + name + "! ") * times

greet("Alice", 3)  # works
try:
    greet(123, 3)  # raises BeartypeCallHintParamViolation at call time
except Exception as e:
    print(e)

# typeguard: decorator-based runtime checking
from typeguard import typechecked

@typechecked
def add(x: int, y: int) -> int:
    return x + y

add(1, 2)    # fine
try:
    add(1.5, 2)  # raises TypeCheckError: argument "x" (float) is not an instance of int
except Exception as e:
    print(e)
